var TSU_REQ_ACT_TP = stp.getValue("/Document/BaselnRpt/ReqForActn","Tp");
stp.writeLog("Request Action Type: "+TSU_REQ_ACT_TP[0]);

var GetTxId1= stp.getValue("/Document/BaselnRpt/TxId","Id");
var GetTxId=GetTxId1[0];
var bu=stp.getTSUUnitCode();
stp.writeLog("bu="+bu);
var fld_list1  = stp.addFieldList(null,"C_MAIN_REF");
fld_list1 = stp.addFieldList(fld_list1,"TSU_INSTR_TP");
var sql_condition1 = stp.addSQLCondition(null,"TSU_TID",GetTxId);
sql_condition1 = stp.addSQLCondition(sql_condition1,"C_UNIT_CODE",bu);
var result1 = stp.executeQuery("TSUM_EM_BASELINE",fld_list1,sql_condition1);
var TSU_INSTR_TYPE = stp.getDBFieldValue(result1,"TSU_INSTR_TP");
var mainRef = stp.getDBFieldValue(result1,"C_MAIN_REF");
stp.writeLog("TSU_INSTR_TP="+TSU_INSTR_TYPE);
stp.writeLog("mainRef="+mainRef);
stp.updateFieldValue("/root/domData","C_MAIN_REF",mainRef);
stp.updateFieldValue("/root/domData","C_TRX_REF",mainRef);
stp.updateFieldValue("","TSU_IDX",mainRef);
if ( TSU_REQ_ACT_TP[0]== undefined)
{
	stp.updateFieldValue("/root/domData","TSUR2_REQ_ACT_TP","EMPT");	
	stp.updateFieldValue("/root/domData","TSU_REQ_ACT_DESC","");
	stp.setNodeAttribute("/root/domData/TSU_REQ_ACT_DESC");
}
//for reqforactn end
var RptTp1 =stp.getValue("/Document/BaselnRpt/RptTp","Tp");
RptTp=RptTp1[0];
stp.writeLog("RptTp="+RptTp);
stp.updateFieldValue("/root/domData","STP_DO_MAINTABLE","TSUM_EM_BASELINE");

if (RptTp == "CURR")
{
	stp.writeLog("Begin: function R2BaselineReport CURR");
	//get  C_MAIN_REF,SHORT_NAME,TSU_TRX_AMD,TSUR2_TRX_STATUS,TSU_TRX_STATUS from table TSUM_MASTER  -S
	var fld_list  = stp.addFieldList(null,"SHORT_NAME");
	fld_list      = stp.addFieldList(fld_list,"TSU_TRX_AMD");
	fld_list      = stp.addFieldList(fld_list,"TSUR2_TRX_STATUS");
	fld_list      = stp.addFieldList(fld_list,"TSU_TRX_STATUS");
	fld_list      = stp.addFieldList(fld_list,"TSU_PO_ID");
	var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId);
	sql_condition     = stp.addSQLCondition(sql_condition,"C_MAIN_REF",mainRef); 
	sql_condition     = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu); 
	var result        = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
	var Shortname	= stp.getDBFieldValue(result,"SHORT_NAME");
	stp.writeLog("Shortname="+Shortname);
	var Amstatus = stp.getDBFieldValue(result,"TSU_TRX_STATUS"); 
	stp.writeLog("Amstatus="+Amstatus);
	var Custatus = stp.getDBFieldValue(result,"TSUR2_TRX_STATUS");
	stp.writeLog("Custatus="+Custatus);
	var Amtype 	 = stp.getDBFieldValue(result,"TSU_TRX_AMD");
	stp.writeLog("Amtype="+Amtype);
	var POID      = stp.getDBFieldValue(result,"TSU_PO_ID");
	stp.writeLog("POID="+POID);
	//get  C_MAIN_REF,SHORT_NAME,TSU_TRX_AMD,TSUR2_TRX_STATUS,TSU_TRX_STATUS from table TSUM_MASTER  -E

	//get TSU_COMM_REF for OCBC--SIBOS2009 Start
	var tsupostfin="Y";
	var fld_list1     = stp.addFieldList(null,"TSU_COMM_REF");
	var sql_condition1 = stp.addSQLCondition(null,"TSU_PO_ID",POID);
	sql_condition1     = stp.addSQLCondition(sql_condition1,"TSU_POST_FIN",tsupostfin); 
	sql_condition1     = stp.addSQLCondition(sql_condition1,"C_UNIT_CODE",bu); 
	var result1       = stp.executeQuery("TSUM_MASTER",fld_list1,sql_condition1);
	var commref      = stp.getDBFieldValue(result1,"TSU_COMM_REF");
	stp.writeLog("commref="+commref);
	if(commref== '' || commref== null || commref == undefined){
		fld_list1     = stp.addFieldList(null,"TSU_COMM_REF");
		sql_condition1 = stp.addSQLCondition(null,"TSU_PO_ID",POID);
		sql_condition1     = stp.addSQLCondition(sql_condition1,"C_UNIT_CODE",bu); 
		result1       = stp.executeQuery("TSUM_EM_BASELINE",fld_list1,sql_condition1);
		commref      = stp.getDBFieldValue(result1,"TSU_COMM_REF");
		stp.writeLog("commref EM BASELINE="+commref);
	}
	stp.updateFieldValue("/root/domData","TSU_PO_ID",POID);
