		var result        = 	stp.getTableMultiDataToArray("TSUM_LEDGER",fld_list,sql_condition, "ORDER BY I_EVENT_TIMES DESC");
		result = result[0];
		var MessageID	= stp.getDBFieldValue(result,"TSU_MESSAGE_ID");
		stp.writeLog("MessageID="+MessageID);*/
		//get amendment message id from table TSUM_LEDGER  -E
		var BmainRef = stp.getValue("/Document/BaselnRpt/UsrTxRef","Id");
		stp.updateFieldValue("","C_MAIN_REF",BmainRef[0]);
		stp.updateFieldValue("","C_TRX_REF",BmainRef[0]);
		stp.updateFieldValue("","C_UNIT_CODE",bu);

		stp.updateFieldValue("/root/domData","SPECIAL_METHOD","Y");
		stp.writeLog("011 Lodge--Special");
		stp.updateFieldValue("/root/domData","DELETE_ALL_DATA","Y"); 
		stp.writeLog("011 Lodge--Delete All");
