		stp.updateFieldValue("/root/domData/R2PartyInfo/Buyer","TSU_IDX",0);
		stp.updateFieldValue("/root/domData/R2PartyInfo/Seller","TSU_IDX",0);
		stp.deleNode("/root/domData/R2PartyInfo","BillTo");
		stp.deleNode("/root/domData/R2PartyInfo","ShipTo");
		stp.deleNode("/root/domData/R2PartyInfo","Consignee");
		stp.deleNode("/root/domData/R2PartyInfo","Consignor");
		stp.writeLog("011 Lodge--Replace"); 	
		//replace node -S	
		var xlist = new Array(7);
		stp.writeLog("011 Lodge--Replace1");
		xlist[0] = "R2InvolvedPartyInfoRe";
		stp.writeLog("011 Lodge--Replace2");
		xlist[1] = "R2GoodsRe";
		xlist[2] = "R2PaymentTermsRe";
		xlist[3] = "R2SettlementTermsRe";
		xlist[4] = "R2PaymentObligationRe";
		xlist[5] = "R2DatasetRequiredRe";
		xlist[6] = "UserDefinedInformationRe";
		stp.writeLog("011 Lodge--Replace3");
		//stp.replaceDoSpecial(xlist,"011"); 
		stp.replaceDoSpecial(xlist,"tsmt.011.001.03");
		//replace node -E
		stp.writeLog("End 011 Lodge");
	}    


	if (Amstatus == "AMRQ" && TSU_INSTR_TYPE!="LODG")
	{
		stp.writeLog("Amtype.length="+Amtype.length());

		if((Amtype=="006" && Custatus=="AMRQ")||(Amtype==" ")||(Amtype=="005" && Shortname=="001"))
