			stp.writeLog("start A");
			stp.updateFieldValue("/root/domData","STP_PARENT_TABLE","TSUM_EM_BASELINE");
			stp.updateFieldValue("/root/domData","TSU_TRX_AMD","011");	
		  stp.deleNode("/root/domData/R2GoodsRe/R2LineItemDetails7","ProductIdentifier");
